              )}
            </>
          )}

          {/* Account Statistics */}
          {displayAccounts?.length > 0 && (
            <div className="mt-12">
              <h3 className="text-lg font-semibold text-foreground mb-6">Account Statistics</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
